"""
TOML config parser.
"""
import toml
from typing import Dict, Tuple, Any
from pipeline_types import Config
from pipeline_parser import ParseError


def parse_config_file(config_path: str) -> Config:
    try:
        with open(config_path, 'r') as f:
            data = toml.load(f)
    except toml.TomlDecodeError as e:
        raise ParseError(f"Invalid TOML syntax: {str(e)}")
    except FileNotFoundError:
        raise ParseError(f"Config file not found: {config_path}")

    config = Config()
    if 'entry' in data:
        config.entry = data['entry']
    if 'clean_cwd' in data:
        config.clean_cwd = data['clean_cwd']
    if 'env' in data:
        if isinstance(data['env'], dict):
            config.env = {k: str(v) for k, v in data['env'].items()}
        else:
            raise ParseError("env must be a table in config")

    # Parse cache configuration
    if 'cache' in data:
        cache_data = data['cache']
        if isinstance(cache_data, dict):
            if 'enabled' in cache_data:
                config.cache_enabled = cache_data['enabled']
            if 'location' in cache_data:
                config.cache_location = str(cache_data['location'])
        else:
            raise ParseError("cache must be a table in config")

    # Parse force_refresh
    if 'force_refresh' in data:
        fr_data = data['force_refresh']
        if isinstance(fr_data, list):
            config.force_refresh = [str(item) for item in fr_data]
        else:
            raise ParseError("force_refresh must be a list in config")

    return config


def _parse_value(val: str) -> Any:
    """Convert string to appropriate type."""
    val = val.strip()
    if val.isdigit():
        return int(val)
    if val.replace('.', '').isdigit():
        return float(val)
    if val.upper() in ('TRUE', 'FALSE'):
        return val.upper() == 'TRUE'
    if (val.startswith('"') and val.endswith('"')) or (val.startswith("'") and val.endswith("'")):
        return val[1:-1]
    return val


def parse_entry_task(entry_str: str) -> Tuple[str, Dict[str, Any]]:
    parens_start = entry_str.find('(')
    if parens_start == -1:
        return entry_str.strip(), {}
    if not entry_str.endswith(')'):
        raise ParseError(f"Invalid entry task: unclosed parenthesis in '{entry_str}'")

    task_name = entry_str[:parens_start].strip()
    args_str = entry_str[parens_start + 1:-1]
    if not args_str.strip():
        return task_name, {}

    params = {}
    parts = []
    current = ""
    in_quotes = False
    quote_char = None
    depth = 0

    for ch in args_str:
        if ch in ('"', "'") and (not in_quotes or quote_char == ch):
            in_quotes = not in_quotes
            quote_char = ch if in_quotes else None
            current += ch
        elif not in_quotes:
            if ch in '([':
                depth += 1
            elif ch in ')]':
                depth -= 1
            elif ch == ',' and depth == 0:
                if current.strip():
                    parts.append(current.strip())
                current = ""
            else:
                current += ch
        else:
            current += ch

    if current.strip():
        parts.append(current.strip())

    for part in parts:
        if '=' in part:
            key, val = part.split('=', 1)
            params[key.strip()] = _parse_value(val)
        else:
            params[len(params)] = _parse_value(part)

    return task_name, params

"""
Main orchestrator for pipeline execution.
"""
import time
from pathlib import Path
from typing import Dict, List, Optional, Set, Any

from pipeline_types import Task, JobResult, Config
from pipeline_parser import parse_pipeline_file, ParseError, parse_call_args
from config_parser import parse_config_file, parse_entry_task
from executor import TaskExecutor


class Orchestrator:
    """
    Orchestrates pipeline execution: resolves dependencies and schedules tasks.
    """

    def __init__(
        self, workspace: Path, output_dir: Path,
        config: Optional[Config] = None, env: Optional[Dict[str, str]] = None
    ):
        self.workspace = workspace
        self.output_dir = output_dir
        self.config = config or Config()
        self.env = env or {}

        self.env.update(self.config.env)
        self.executor = TaskExecutor(workspace, output_dir, self.env)

        self.tasks: Dict[str, Task] = {}
        self.executed_tasks: Dict[str, List[JobResult]] = {}
        self.running_tasks: Set[str] = set()
        self.job_results: Dict[str, JobResult] = {}

    def register_tasks(self, parsed_tasks: List[Task]):
        """Register tasks from parsed pipeline."""
        for task in parsed_tasks:
            if task.name in self.tasks:
                raise ValueError(f"Duplicate task definition: {task.name}")
            self.tasks[task.name] = task

    def resolve_entry_task(self, entry_spec: Optional[str] = None) -> tuple:
        """Determine which task is the entry point and with what parameters."""
        if entry_spec:
            return parse_entry_task(entry_spec)

        if 'main' in self.tasks:
            return 'main', {}

        if len(self.tasks) == 1:
            return list(self.tasks.keys())[0], {}

        raise ValueError("No entry task specified and no default 'main' or single task found")

    def _resolve_params_from_call(self, task: Task, call_params: Dict[str, Any]) -> Dict[str, Any]:
        """Resolve parameters from a task call, applying defaults and type checking."""
        resolved = {}
        param_by_name = {}

        for i, param_def in enumerate(task.params):
            if param_def.has_default:
                resolved[param_def.name] = param_def.default_value
            param_by_name[param_def.name] = param_def

        for key, value in call_params.items():
            if isinstance(key, int):
                if key < len(task.params):
                    param_def = task.params[key]
                    resolved[param_def.name] = self._cast_value(value, param_def)
            else:
                if key in param_by_name:
                    resolved[key] = self._cast_value(value, param_by_name[key])
                else:
                    raise ValueError(f"Unknown parameter: {key}")

        return resolved

    def _cast_value(self, value: str, param_def) -> Any:
        """Cast a value from the task call to the parameter's expected type."""
        type_name = param_def.param_type.name
        if type_name == 'STRING':
            return str(value)
        if type_name == 'INT':
            try:
                return int(value)
            except ValueError:
                raise ValueError(f"Invalid integer value: {value}")
        if type_name == 'FLOAT':
            try:
                return float(value)
            except ValueError:
                raise ValueError(f"Invalid float value: {value}")
        if type_name == 'BOOL':
            return str(value).upper() in ('TRUE', '1', 'YES', 'T')
        if type_name == 'LIST':
            return [v.strip().strip('"').strip("'") for v in value.split(',')] if value else []
        return value

    def resolve_dependencies(self, task: Task, params: Dict[str, Any]) -> List[JobResult]:
        """Execute tasks in the requires block."""
        if not task.requires:
            return []

        results = []
        pos = 0
        text = task.requires.strip()

        while pos < len(text):
            while pos < len(text) and text[pos].isspace():
                pos += 1

            if pos >= len(text) or text[pos] == '}':
                break

            start = pos
            while pos < len(text) and (text[pos].isalnum() or text[pos] == '_'):
                pos += 1
            ident = text[start:pos]

            if ident == 'fails':
                if pos >= len(text) or text[pos] != '(':
                    continue
                depth = 1
                start = pos + 1
                while pos < len(text) and depth > 0:
                    if text[pos] == '(':
                        depth += 1
                    elif text[pos] == ')':
                        depth -= 1
                    pos += 1
                task_call = text[start:pos-1]
                try:
                    sub_result = self._execute_task_from_call(task_call, params)
                    if sub_result:
                        results.append(sub_result)
                except Exception:
                    pass
            elif ident in self.tasks:
                if pos < len(text) and text[pos] == '(':
                    depth = 1
                    start = pos + 1
                    while pos < len(text) and depth > 0:
                        if text[pos] == '(':
                            depth += 1
                        elif text[pos] == ')':
                            depth -= 1
                        pos += 1
                    task_call = text[start:pos-1]
                else:
                    task_call = ident

                sub_result = self._execute_task_from_call(task_call, params)
                results.append(sub_result)
                if sub_result and sub_result.exit_code != 0:
                    return results
            else:
                pos += 1

        return results

    def _execute_task_from_call(self, call_str: str, parent_params: Dict[str, Any]) -> Optional[JobResult]:
        """Execute a sub-task based on a call string like 'task_name(1, x=2)' or just 'task_name'."""
        paren_idx = call_str.find('(')

        if paren_idx == -1:
            task_name = call_str.strip()
            call_params = {}
        else:
            task_name = call_str[:paren_idx].strip()
            if not call_str.endswith(')'):
                raise ValueError(f"Unclosed parenthesis in task call: {call_str}")

            args_str = call_str[paren_idx + 1:-1]
            if not args_str.strip():
                call_params = {}
            else:
                call_params = parse_call_args(args_str)

        if task_name not in self.tasks:
            raise ValueError(f"Unknown task: {task_name}")

        task = self.tasks[task_name]
        resolved_params = self._resolve_params_from_call(task, call_params)

        parent_job_id = None
        if hasattr(self, '_current_job_id'):
            parent_job_id = self._current_job_id

        return self.executor.execute_task(
            task, resolved_params, parent_job_id,
            global_cache_enabled=self.config.cache_enabled,
            global_cache_location=self.config.cache_location,
            force_refresh=self.config.force_refresh
        )

    def _execute_task(self, task_name: str, params: Dict[str, Any],
                     parent_job_id: Optional[int] = None) -> JobResult:
        """Execute a task, resolving dependencies first."""
        task = self.tasks[task_name]

        if task.requires:
            self.resolve_dependencies(task, params)

        return self.executor.execute_task(
            task, params, parent_job_id,
            global_cache_enabled=self.config.cache_enabled,
            global_cache_location=self.config.cache_location,
            force_refresh=self.config.force_refresh
        )

    def execute(self, entry_spec: Optional[str] = None) -> int:
        """Execute the pipeline starting from the entry task. Returns exit code: 0 for success, 1 for failure."""
        entry_task_name, entry_params = self.resolve_entry_task(entry_spec)

        result = self._execute_task(entry_task_name, entry_params, None)

        if result.exit_code != 0:
            print(f"Entry task failed with exit code {result.exit_code}")
            return 1

        return 0

"""
Pipeline file parser.
"""
import re
from typing import List, Dict, Optional, Any
from pipeline_types import Task, Parameter, SuccessCriterion, ParamType
from config_parser import _parse_value


class ParseError(Exception):
    """Syntax error in pipeline file."""
    def __init__(self, message: str, position: int = -1, line: int = -1):
        msg = f"SYNTAX_ERROR:{message}"
        if position != -1:
            msg += f" at position {position}"
        if line != -1:
            msg += f" (line {line})"
        super().__init__(msg)
        self.message = message


def _find_matching_brace(text: str, start: int) -> int:
    if text[start] != '{':
        raise ParseError("Expected '{'")
    depth, pos = 1, start + 1
    while pos < len(text) and depth > 0:
        if text[pos] == '{':
            depth += 1
        elif text[pos] == '}':
            depth -= 1
        pos += 1
    if depth != 0:
        raise ParseError("Unclosed block")
    return pos - 1


def _strip_value(s: str) -> str:
    s = s.strip()
    if s and ((s.startswith('"') and s.endswith('"')) or (s.startswith("'") and s.endswith("'"))):
        return s[1:-1]
    return s


def _split_comma_separated(text: str) -> List[str]:
    """Split by commas outside of quotes."""
    parts = []
    current = ""
    in_quotes = False
    quote_char = None

    for ch in text:
        if ch in ('"', "'") and (not in_quotes or quote_char == ch):
            in_quotes = not in_quotes
            quote_char = ch if in_quotes else None
            current += ch
        elif ch == ',' and not in_quotes:
            if current.strip():
                parts.append(current.strip())
            current = ""
        else:
            current += ch
    if current.strip():
        parts.append(current.strip())
    return parts


def parse_pipeline_file(content: str) -> List[Task]:
    # Remove comments
    content = ''.join(line[:line.index('//')] if '//' in line else line for line in content.split('\n'))

    tasks = []
    task_pattern = r'\btask\s+([a-zA-Z_][a-zA-Z0-9_]*)\s*\{'
    pos = 0

    while match := re.search(task_pattern, content[pos:]):
        task_start = pos + match.start()
        task_name = match.group(1)
        brace_start = task_start + match.end() - 1  # position of '{'
        brace_end = _find_matching_brace(content, brace_start)
        task_text = content[brace_start + 1:brace_end].strip()

        try:
            tasks.append(parse_task_body(task_name, task_text))
        except ParseError as e:
            raise ParseError(f"Error parsing task '{task_name}': {e.message}")
        pos = brace_end + 1

    return tasks


def parse_task_body(name: str, body: str) -> Task:
    task = Task(name=name)
    blocks = _extract_blocks(body)

    if 'params' in blocks:
        task.params = parse_params(blocks['params'])
    if 'run' in blocks:
        task.run = blocks['run'].strip()
    if 'success' in blocks:
        task.success = parse_success(blocks['success'])
    if 'requires' in blocks:
        task.requires = blocks['requires'].strip()
    if 'output' in blocks:
        task.output = _strip_value(blocks['output'])
    if 'timeout' in blocks:
        task.timeout = float(blocks['timeout'].strip())
    if 'cache' in blocks:
        task.cache = parse_cache_config(blocks['cache'])

    return task


def _extract_blocks(body: str) -> Dict[str, str]:
    """Extract named blocks from body text."""
    blocks = {}
    keywords = ['params:', 'run:', 'success:', 'requires:', 'output:', 'timeout:', 'cache:']
    pos = 0

    while pos < len(body):
        while pos < len(body) and body[pos].isspace():
            pos += 1
        if pos >= len(body):
            break

        matched = False
        for kw in keywords:
            if body.startswith(kw, pos):
                block_name = kw.rstrip(':')
                pos += len(kw)
                while pos < len(body) and body[pos].isspace():
                    pos += 1

                if block_name in ('params', 'run', 'success', 'requires', 'cache'):
                    if pos < len(body) and body[pos] == '{':
                        end = _find_matching_brace(body, pos)
                        blocks[block_name] = body[pos + 1:end].strip()
                        pos = end + 1
                else:
                    end = pos
                    while end < len(body) and body[end] not in ('\n', ';'):
                        end += 1
                    blocks[block_name] = body[pos:end].strip()
                    pos = end
                matched = True
                break
        if not matched:
            pos += 1

    return blocks


def parse_params(text: str) -> List[Parameter]:
    params = []
    for segment in _split_comma_separated(text):
        if ':' not in segment:
            raise ParseError(f"Invalid parameter definition: {segment}")

        name, type_and_default = segment.split(':', 1)
        name = name.strip()
        type_str = type_and_default.strip()

        default_value = None
        has_default = False
        if '=' in type_str:
            parts = type_str.split('=', 1)
            type_str = parts[0].strip()
            default_str = parts[1].strip().rstrip(';')
            default_value = _parse_value(default_str)
            has_default = True

        type_str = type_str.rstrip(';').strip()

        if type_str == 'list':
            match = re.search(r'list\s*\[([a-zA-Z_][a-zA-Z0-9_]*)\]', segment)
            if match:
                params.append(Parameter(name=name, param_type=ParamType.LIST,
                                       default_value=default_value, has_default=has_default))
                continue

        type_map = {'string': ParamType.STRING, 'int': ParamType.INT,
                   'float': ParamType.FLOAT, 'bool': ParamType.BOOL}
        if type_str not in type_map:
            raise ParseError(f"Unknown parameter type: {type_str}")
        params.append(Parameter(name=name, param_type=type_map[type_str],
                               default_value=default_value, has_default=has_default))

    return params


def parse_cache_config(text: str) -> CacheConfig:
    """Parse cache configuration block."""
    cache_config = CacheConfig()

    lines = text.strip().split('\n')
    for line in lines:
        line = line.strip()
        if not line or line.startswith('//'):
            continue

        # Remove trailing semicolon if present
        line = line.rstrip(';')

        if ':' in line:
            key, value = line.split(':', 1)
            key = key.strip()
            value = value.strip()

            if key == 'enabled':
                cache_config.enabled = value.upper() == 'TRUE'
            elif key == 'strategy':
                cache_config.strategy = value.strip('"').strip("'")
            elif key == 'location':
                cache_config.location = value.strip('"').strip("'")
            elif key == 'version':
                cache_config.version = value.strip('"').strip("'")
            elif key == 'ttl':
                cache_config.ttl = parse_cache_ttl(value)
            elif key == 'key':
                cache_config.key = parse_cache_key(value)

    return cache_config


def parse_cache_ttl(text: str) -> CacheTTL:
    """Parse TTL configuration block."""
    ttl = CacheTTL()

    # Remove outer braces if present
    text = text.strip()
    if text.startswith('{') and text.endswith('}'):
        text = text[1:-1].strip()

    lines = text.split('\n')
    for line in lines:
        line = line.strip().rstrip(';')
        if not line or line.startswith('//'):
            continue

        if ':' in line:
            key, value = line.split(':', 1)
            key = key.strip()
            value = int(value.strip())

            if key == 'seconds':
                ttl.seconds = value
            elif key == 'minutes':
                ttl.minutes = value
            elif key == 'hours':
                ttl.hours = value
            elif key == 'days':
                ttl.days = value

    return ttl


def parse_cache_key(text: str) -> CacheKey:
    """Parse cache key configuration block."""
    key = CacheKey()

    # Remove outer braces if present
    text = text.strip()
    if text.startswith('{') and text.endswith('}'):
        text = text[1:-1].strip()

    lines = text.split('\n')
    for line in lines:
        line = line.strip().rstrip(';')
        if not line or line.startswith('//'):
            continue

        if ':' in line:
            key, value = line.split(':', 1)
            key = key.strip()
            value = value.strip()

            if key == 'include':
                # Parse list of parameters
                values = _split_comma_separated(value.strip("[]"))
                key.include = [v.strip().strip('"').strip("'") for v in values]
            elif key == 'exclude':
                # Parse list of parameters
                values = _split_comma_separated(value.strip("[]"))
                key.exclude = [v.strip().strip('"').strip("'") for v in values]

    return key


def parse_success(text: str) -> List[SuccessCriterion]:
    """Parse success criteria block."""
    criteria = []
    pos = 0

    while pos < len(text):
        while pos < len(text) and text[pos].isspace():
            pos += 1
        if pos >= len(text):
            break

        name_match = re.match(r'([a-zA-Z_][a-zA-Z0-9_]*)\s*:', text[pos:])
        if name_match:
            name = name_match.group(1)
            colon_pos = pos + name_match.end()
            while colon_pos < len(text) and text[colon_pos].isspace():
                colon_pos += 1
            if colon_pos < len(text) and text[colon_pos] == '{':
                brace_end = _find_matching_brace(text, colon_pos)
                criteria.append(SuccessCriterion(name, text[colon_pos + 1:brace_end].strip()))
                pos = brace_end + 1
            else:
                pos += 1
        else:
            pos += 1

    return criteria


def parse_call_args(args_str: str) -> Dict[str, Any]:
    """Parse arguments from a task call."""
    args = {}
    if not args_str.strip():
        return args

    current = ""
    in_quotes = False
    quote_char = None
    depth = 0

    for ch in args_str:
        if ch in ('"', "'") and (not in_quotes or quote_char == ch):
            in_quotes = not in_quotes
            quote_char = ch if in_quotes else None
            current += ch
        elif not in_quotes:
            if ch == '(':
                depth += 1
            elif ch == ')':
                depth -= 1
            elif ch == ',' and depth == 0:
                if current.strip():
                    _add_arg(current.strip(), args)
                current = ""
            else:
                current += ch
        else:
            current += ch

    if current.strip():
        _add_arg(current.strip(), args)
    return args


def _add_arg(arg: str, args: Dict):
    """Add a parsed argument to the args dict."""
    arg = arg.strip()
    if '=' in arg:
        key, val = arg.split('=', 1)
        key, val = key.strip(), val.strip()
        if (val.startswith('"') and val.endswith('"')) or (val.startswith("'") and val.endswith("'")):
            val = val[1:-1]
        if val.isdigit():
            val = int(val)
        elif val.replace('.', '').isdigit():
            try:
                val = float(val)
            except ValueError:
                pass
        elif val.upper() in ('TRUE', 'FALSE'):
            val = val.upper() == 'TRUE'
        args[key] = val
    else:
        val = arg
        if val.isdigit():
            val = int(val)
        elif val.replace('.', '').isdigit():
            try:
                val = float(val)
            except ValueError:
                pass
        elif val.upper() in ('TRUE', 'FALSE'):
            val = val.upper() == 'TRUE'
        args[len(args)] = val

"""
Expression evaluator for success criteria and requires blocks.
"""
import re
from typing import Any, Dict, List, Optional
from pathlib import Path


class EvaluationError(Exception):
    """Error evaluating expression."""
    pass


class ExpressionEvaluator:
    """
    Evaluates expressions in the pipeline language.
    Supports:
    - Variables, literals (int, float, string, bool)
    - Arithmetic (+, -, *, /, %, comparisons)
    - Logical operations (&&, ||, !)
    - String concatenation (%)
    - Arrays/indexing
    - Control flow (if/else, for loops, while loops)
    - Builtin functions (len, contains, equals, exists, fail)
    - Parameter substitution ($ params)
    """

    def __init__(self, workspace: Path, output_dir: Optional[Path] = None):
        self.workspace = workspace
        self.output_dir = output_dir
        self._functions = {
            'len': self._len_func,
            'contains': self._contains_func,
            'equals': self._equals_func,
            'exists': self._exists_func,
            'fail': self._fail_func,
        }

    def evaluate(self, expr: str, context: Dict[str, Any]) -> Any:
        """
        Evaluate an expression string with the given context.
        Returns the result of the evaluation.
        """
        if not expr or not expr.strip():
            return True  # Empty success criteria is considered True

        self._context = context.copy()
        self._result = None
        self._pos = 0
        self._expr = expr.strip()

        result = self._parse_expression()
        return result

    def parse_and_evaluate(self, expr: str, context: Dict[str, Any]) -> Any:
        """Parse and evaluate a block of statements."""
        self._context = context.copy()
        self._result = None
        self._pos = 0
        self._expr = expr.strip()

        return self._parse_block()

    # ============================================================
    # Parsing helpers
    # ============================================================

    def _skip_whitespace(self):
        """Skip whitespace characters."""
        while self._pos < len(self._expr) and self._expr[self._pos].isspace():
            self._pos += 1

    def _peek(self, offset: int = 0) -> str:
        """Look at the character at current position + offset."""
        idx = self._pos + offset
        if idx < len(self._expr):
            return self._expr[idx]
        return '\0'

    def _consume(self, expected: Optional[str] = None) -> str:
        """Consume and return the current character, optionally checking it."""
        self._skip_whitespace()
        if self._pos >= len(self._expr):
            if expected is None:
                return '\0'
            raise EvaluationError(f"Unexpected end of expression, expected '{expected}'")

        ch = self._expr[self._pos]
        if expected is not None and ch != expected:
            raise EvaluationError(f"Expected '{expected}', got '{ch}'")

        self._pos += 1
        return ch

    def _parse_identifier(self) -> str:
        """Parse an identifier (variable name, function name)."""
        self._skip_whitespace()

        if self._pos >= len(self._expr):
            raise EvaluationError("Expected identifier, found end of expression")

        start = self._pos
        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch.isalnum() or ch == '_':
                self._pos += 1
            else:
                break

        if self._pos == start:
            raise EvaluationError(f"Expected identifier, found '{self._expr[self._pos]}'")

        return self._expr[start:self._pos]

    def _parse_string(self) -> str:
        """Parse a quoted string."""
        self._skip_whitespace()
        if self._pos >= len(self._expr):
            raise EvaluationError("Expected string, found end of expression")

        quote = self._expr[self._pos]
        if quote not in ('"', "'"):
            raise EvaluationError(f"Expected string, found '{quote}'")

        self._pos += 1
        result = []

        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch == '\\':
                # Handle escape sequences
                self._pos += 1
                if self._pos < len(self._expr):
                    esc = self._expr[self._pos]
                    if esc == 'n':
                        result.append('\n')
                    elif esc == 't':
                        result.append('\t')
                    elif esc == 'r':
                        result.append('\r')
                    elif esc in ('"', "'", '\\'):
                        result.append(esc)
                    else:
                        result.append(esc)
                    self._pos += 1
                else:
                    result.append('\\')
            elif ch == quote:
                self._pos += 1
                break
            else:
                result.append(ch)
                self._pos += 1

        return ''.join(result)

    def _parse_number(self) -> Any:
        """Parse a number (int or float)."""
        self._skip_whitespace()

        start = self._pos
        has_decimal = False

        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch == '.' and not has_decimal:
                has_decimal = True
                self._pos += 1
            elif ch.isdigit():
                self._pos += 1
            else:
                break

        if self._pos == start:
            raise EvaluationError(f"Expected number, found '{self._expr[self._pos]}'")

        num_str = self._expr[start:self._pos]
        if has_decimal:
            return float(num_str)
        return int(num_str)

    def _parse_list(self) -> List[Any]:
        """Parse a list literal [a, b, c]."""
        self._skip_whitespace()
        if self._peek() != '[':
            raise EvaluationError(f"Expected '[', found '{self._peek()}'")

        self._pos += 1  # consume '['

        result = []

        if self._peek() == ']':
            self._pos += 1
            return result

        while self._pos < len(self._expr):
            self._skip_whitespace()
            value = self._parse_expression()
            result.append(value)

            self._skip_whitespace()
            if self._peek() == ',':
                self._pos += 1
                continue
            elif self._peek() == ']':
                self._pos += 1
                break
            else:
                raise EvaluationError(f"Expected ',' or ']', found '{self._peek()}'")

        return result

    # ============================================================
    # Expression parsing (recursive descent)
    # ============================================================

    def _parse_expression(self) -> Any:
        """Parse an expression."""
        self._skip_whitespace()
        return self._parse_or()

    def _parse_or(self) -> Any:
        """Parse OR expressions (&&, ||)."""
        left = self._parse_and()

        self._skip_whitespace()
        while self._peek() == '&' and self._peek(1) == '&':
            self._pos += 2  # consume '&&'
            right = self._parse_and()
            left = left and self._to_bool(right)
            self._skip_whitespace()

        while self._peek() == '|' and self._peek(1) == '|':
            self._pos += 2  # consume '||'
            right = self._parse_and()
            left = left or self._to_bool(right)
            self._skip_whitespace()

        return left

    def _parse_and(self) -> Any:
        """Parse AND expressions."""
        left = self._parse_equality()

        self._skip_whitespace()
        while self._peek() == '&' and self._peek(1) == '&':
            self._pos += 2
            right = self._parse_equality()
            left = left and self._to_bool(right)
            self._skip_whitespace()

        return left

    def _parse_equality(self) -> Any:
        """Parse equality expressions (==, !=)."""
        left = self._parse_comparison()

        self._skip_whitespace()
        while self._peek() == '=' and self._peek(1) == '=':
            self._pos += 2
            right = self._parse_comparison()
            left = left == right
            self._skip_whitespace()

        while self._peek() == '!' and self._peek(1) == '=':
            self._pos += 2
            right = self._parse_comparison()
            left = left != right
            self._skip_whitespace()

        return left

    def _parse_comparison(self) -> Any:
        """Parse comparison expressions (<, >, <=, >=)."""
        left = self._parse_additive()

        self._skip_whitespace()
        while True:
            if self._peek() == '<' and self._peek(1) == '=':
                self._pos += 2
                right = self._parse_additive()
                left = left <= right
            elif self._peek() == '>':
                if self._peek(1) == '=':
                    self._pos += 2
                    right = self._parse_additive()
                    left = left >= right
                else:
                    self._pos += 1
                    right = self._parse_additive()
                    left = left > right
            elif self._peek() == '<':
                self._pos += 1
                right = self._parse_additive()
                left = left < right
            else:
                break

            self._skip_whitespace()

        return left

    def _parse_additive(self) -> Any:
        """Parse addition and subtraction."""
        left = self._parse_term()

        self._skip_whitespace()
        while self._peek() in ('+', '-'):
            op = self._peek()
            self._pos += 1
            right = self._parse_term()

            if op == '+':
                left = left + right
            else:
                left = left - right

            self._skip_whitespace()

        return left

    def _parse_term(self) -> Any:
        """Parse multiplication, division, and modulo."""
        left = self._parse_factor()

        self._skip_whitespace()
        while self._peek() in ('*', '/', '%'):
            op = self._peek()
            self._pos += 1
            right = self._parse_factor()

            if op == '*':
                left = left * right
            elif op == '/':
                left = left / right
            elif op == '%':
                left = left % right

            self._skip_whitespace()

        return left

    def _parse_factor(self) -> Any:
        """Parse unary operators and primary expressions."""
        self._skip_whitespace()

        # Handle unary + and -
        if self._peek() == '+':
            self._pos += 1
            return self._parse_factor()
        elif self._peek() == '-':
            self._pos += 1
            return -self._parse_number() if self._expr[self._pos].isdigit() else -self._parse_factor()
        elif self._peek() == '!':
            self._pos += 1
            value = self._parse_factor()
            return not self._to_bool(value)

        return self._parse_primary()

    def _parse_primary(self) -> Any:
        """Parse primary expressions (literals, variables, function calls, etc.)."""
        self._skip_whitespace()

        # Handle parameter substitution ${...}
        if self._peek() == '$' and self._peek(1) == '{':
            return self._parse_param_substitution()

        # String literal
        if self._peek() in ('"', "'"):
            return self._parse_string()

        # List literal
        if self._peek() == '[':
            return self._parse_list()

        # Number
        if self._peek().isdigit() or self._peek() == '.':
            return self._parse_number()

        # True/False
        if self._expr.startswith('TRUE', self._pos):
            self._pos += 4
            return True
        if self._expr.startswith('FALSE', self._pos):
            self._pos += 5
            return False

        # Function call
        identifier = self._parse_identifier()
        self._skip_whitespace()
        if self._peek() == '(':
            return self._parse_function_call(identifier)

        # Check if it's a variable
        if identifier in self._context:
            return self._context[identifier]

        # It's an identifier (string value)
        return identifier

    def _parse_param_substitution(self) -> str:
        """Parse ${params.x} or ${workspace}."""
        if not (self._peek() == '$' and self._peek(1) == '{'):
            raise EvaluationError("Expected ${...}")

        self._pos += 2  # consume ${'
        start = self._pos

        depth = 0
        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch == '{':
                depth += 1
            elif ch == '}':
                if depth == 0:
                    break
                depth -= 1
            self._pos += 1

        inner = self._expr[start:self._pos]

        if inner.startswith('params.'):
            param_name = inner[7:]
            if param_name in self._context.get('params', {}):
                return str(self._context['params'][param_name])
            else:
                return f"${{params.{param_name}}}"
        elif inner == 'workspace':
            return str(self.workspace.resolve()) if self.workspace else ""
        elif inner == 'output':
            return str(self.output_dir) if self.output_dir else ""
        else:
            # Try to resolve as variable
            if inner in self._context:
                return str(self._context[inner])
            return f"${{{inner}}}"

    def _parse_function_call(self, func_name: str) -> Any:
        """Parse a function call: func_name(arg1, arg2, ...)."""
        if self._peek() != '(':
            raise EvaluationError(f"Expected '(', found '{self._peek()}'")

        self._pos += 1  # consume '('
        self._skip_whitespace()

        args = []

        if self._peek() == ')':
            self._pos += 1
        else:
            while True:
                self._skip_whitespace()
                arg = self._parse_expression()
                args.append(arg)

                self._skip_whitespace()
                if self._peek() == ',':
                    self._pos += 1
                    continue
                elif self._peek() == ')':
                    self._pos += 1
                    break
                else:
                    raise EvaluationError(f"Expected ',' or ')', found '{self._peek()}'")

        # Execute the function
        if func_name not in self._functions:
            raise EvaluationError(f"Unknown function: {func_name}")

        return self._functions[func_name](args)

    def _parse_block(self) -> Any:
        """Parse a block of statements."""
        while self._pos < len(self._expr):
            self._skip_whitespace()
            if self._pos >= len(self._expr):
                break

            ident = self._parse_identifier()
            if not ident:
                break
            self._skip_whitespace()

            # Variable declaration: var x = 1;
            if self._peek() == ':':
                self._pos += 1
                self._skip_whitespace()
                self._parse_identifier()  # skip type
                self._skip_whitespace()
                self._consume('=')
                self._context[ident] = self._parse_expression()
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                continue

            # For loop: for (int x = 0; x < 10; x = x + 1) { ... }
            if ident == 'for':
                self._consume('(')
                self._parse_identifier()  # type
                var = self._parse_identifier()
                self._skip_whitespace()
                self._consume('=')
                start = self._parse_expression()
                self._skip_whitespace()
                self._consume(';')
                cond = self._parse_expression()
                self._skip_whitespace()
                self._consume(';')
                upd_ident = self._parse_identifier()
                self._skip_whitespace()
                self._consume('=')
                upd_expr = self._parse_expression()
                self._skip_whitespace()
                self._consume(')')
                self._skip_whitespace()
                self._consume('{')
                body = self._collect_block()

                self._context[var] = start
                while self._evaluate_condition(cond):
                    ctx_copy = self._context.copy()
                    sub = ExpressionEvaluator(self.workspace, self.output_dir)
                    sub._context = ctx_copy
                    sub.parse_and_evaluate(body, ctx_copy)
                    self._context.update(sub._context)
                    if upd_ident == var:
                        self._context[var] = (self._context[var] + upd_expr
                                             if isinstance(upd_expr, int)
                                             else upd_expr)
                self._skip_whitespace()
                if self._peek() == '}':
                    self._pos += 1
                continue

            # While loop: while (cond) { ... }
            if ident == 'while':
                self._consume('(')
                cond = self._parse_expression()
                self._consume(')')
                self._skip_whitespace()
                self._consume('{')
                body = self._collect_block()

                while self._evaluate_condition(cond):
                    ctx_copy = self._context.copy()
                    sub = ExpressionEvaluator(self.workspace, self.output_dir)
                    sub._context = ctx_copy
                    sub.parse_and_evaluate(body, ctx_copy)
                    self._context.update(sub._context)

                self._skip_whitespace()
                if self._peek() == '}':
                    self._pos += 1
                continue

            # If/elif/else
            if ident == 'if':
                self._consume('(')
                cond = self._parse_expression()
                self._consume(')')
                self._skip_whitespace()
                self._consume('{')
                then_body = self._collect_block()

                if self._to_bool(self.evaluate(cond, self._context)):
                    ctx_copy = self._context.copy()
                    sub = ExpressionEvaluator(self.workspace, self.output_dir)
                    sub._context = ctx_copy
                    sub.parse_and_evaluate(then_body, ctx_copy)
                    self._context.update(sub._context)

                self._skip_whitespace()
                if self._peek() == '}':
                    self._pos += 1

                # Elif/else chain
                while True:
                    self._skip_whitespace()
                    elif_pos = self._expr.startswith('elif', self._pos)
                    if elif_pos:
                        self._pos += 4
                        self._consume('(')
                        elif_cond = self._parse_expression()
                        self._consume(')')
                        self._skip_whitespace()
                        self._consume('{')
                        elif_body = self._collect_block()

                        if self._to_bool(self.evaluate(elif_cond, self._context)):
                            ctx_copy = self._context.copy()
                            sub = ExpressionEvaluator(self.workspace, self.output_dir)
                            sub._context = ctx_copy
                            sub.parse_and_evaluate(elif_body, ctx_copy)
                            self._context.update(sub._context)

                        self._skip_whitespace()
                        if self._peek() == '}':
                            self._pos += 1
                        continue

                    if self._expr.startswith('else', self._pos):
                        self._pos += 4
                        self._skip_whitespace()
                        self._consume('{')
                        else_body = self._collect_block()

                        ctx_copy = self._context.copy()
                        sub = ExpressionEvaluator(self.workspace, self.output_dir)
                        sub._context = ctx_copy
                        sub.parse_and_evaluate(else_body, ctx_copy)
                        self._context.update(sub._context)

                        self._skip_whitespace()
                        if self._peek() == '}':
                            self._pos += 1
                        continue

                    break
                continue

            # Return statement
            if ident == 'return':
                value = self._parse_expression()
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                return self._to_bool(value)

            # Break
            if ident == 'break':
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                return True

            # Continue
            if ident == 'continue':
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                return True

            # Function call statement: len(x);
            self._skip_whitespace()
            if self._peek() == '(':
                result = self._parse_function_call(ident)
                if isinstance(result, bool) and not result:
                    return False
                self._skip_whitespace()
                if self._peek() == ';':
                    self._pos += 1
                continue

            # Expression statement
            self._pos -= len(ident)
            self._parse_expression()
            self._skip_whitespace()
            if self._peek() == ';':
                self._pos += 1

        return True

    def _collect_block(self) -> str:
        """Collect a block of text until matching brace."""
        start = self._pos
        depth = 0

        while self._pos < len(self._expr):
            ch = self._expr[self._pos]
            if ch == '{':
                depth += 1
            elif ch == '}':
                depth -= 1
                if depth < 0:
                    break
            self._pos += 1

        return self._expr[start:self._pos]

    def _evaluate_condition(self, expr: Any) -> bool:
        """Evaluate a condition to boolean."""
        return self._to_bool(expr)

    def _to_bool(self, value: Any) -> bool:
        """Convert a value to boolean."""
        if isinstance(value, bool):
            return value
        if isinstance(value, (int, float)):
            return value != 0
        if isinstance(value, str):
            return value.lower() in ('true', 'yes', '1', 't')
        if isinstance(value, list):
            return len(value) > 0
        return value is not None

    def _len_func(self, args: List) -> int:
        """Builtin len function."""
        if len(args) != 1:
            raise EvaluationError(f"len() takes exactly 1 argument, got {len(args)}")
        if isinstance(args[0], list):
            return len(args[0])
        raise EvaluationError(f"len() requires a list, got {type(args[0])}")

    def _contains_func(self, args: List) -> bool:
        """Builtin contains function."""
        if len(args) != 2:
            raise EvaluationError(f"contains() takes exactly 2 arguments, got {len(args)}")

        arg1, arg2 = args

        if isinstance(arg1, str) and isinstance(arg2, str):
            return arg2 in arg1

        if isinstance(arg1, list) and isinstance(arg2, str):
            return arg2 in arg1

        # Try to read file contents
        if isinstance(arg1, str):
            # arg1 is a file path, arg2 is what we're looking for
            path = Path(arg1)
            if path.exists():
                try:
                    with open(path, 'r') as f:
                        content = f.read()
                    return arg2 in content
                except:
                    return False

        return False

    def _equals_func(self, args: List) -> bool:
        """Builtin equals function."""
        if len(args) != 2:
            raise EvaluationError(f"equals() takes exactly 2 arguments, got {len(args)}")

        arg1, arg2 = args

        if isinstance(arg1, str):
            # Could be a special value like "stdout", "stderr", "exit_code"
            path = Path(arg1)
            if path.exists():
                try:
                    with open(path, 'r') as f:
                        return f.read().strip() == str(arg2)
                except:
                    return False

        return str(arg1) == str(arg2)

    def _exists_func(self, args: List) -> bool:
        """Builtin exists function."""
        if len(args) != 1:
            raise EvaluationError(f"exists() takes exactly 1 argument, got {len(args)}")

        path = Path(args[0])
        return path.exists()

    def _fail_func(self, args: List) -> bool:
        """Builtin fail function - checks if a task failed."""
        if len(args) != 1:
            raise EvaluationError(f"fail() takes exactly 1 argument, got {len(args)}")

        # This is a special function - we store it for later processing
        # in the requires block evaluation
        task_name = str(args[0])
        self._context['_failed_tasks'] = self._context.get('_failed_tasks', [])
        self._context['_failed_tasks'].append(task_name)
        # For now, assume it's checking if a task failed
        # In the requires block context, we'll use this differently
        return task_name in self._context.get('_completed_tasks', [])

